import React from "react";
import {Pressable, Linking} from "react-native";
import type {ILinkComponent} from "@lmb-it/kitsconcerto-types";
import {Text} from "../../_compat";

const Link: React.FC<ILinkComponent> = ({
    children,
    href,
    onPress,
    isExternal,
    to,
    ...props
}) => {
    const handlePress = (event: any) => {
        if (onPress) {
            onPress(event);
        } else if (href) {
            Linking.openURL(href);
        } else if (to) {
            Linking.openURL(to);
        }
    };

    return (
        <Pressable onPress={handlePress} accessibilityRole="link">
            {typeof children === "string" ? (
                <Text color="primary" underline>{children}</Text>
            ) : (
                children
            )}
        </Pressable>
    );
};

export default Link;
